def is_valid(board, x, y, N):
    """Tahtada verilen koordinatların geçerli olup olmadığını kontrol eder."""
    return (x >= 0 and x < N and y >= 0 and y < N and board[x][y] == -1)

def solve_knights_tour(N):
    """Şövalye turu problemini çözer."""
    board = [[-1 for _ in range(N)] for _ in range(N)]
    move_x = [2, 1, -1, -2, -2, -1, 1, 2]
    move_y = [1, 2, 2, 1, -1, -2, -2, -1]

    board[0][0] = 0  # Şövalyeyi başlangıç hücresine yerleştir
    if not solve_knights_tour_util(N, board, 0, 0, 1, move_x, move_y):
        print("Çözüm yok")
        return False
    else:
        print_solution(board)
        return True

def solve_knights_tour_util(N, board, x, y, move_count, move_x, move_y):
    """Şövalye turu için özyinelemeli yardımcı fonksiyon."""
    if move_count == N * N:
        return True

    for i in range(8):
        next_x = x + move_x[i]
        next_y = y + move_y[i]

        if is_valid(board, next_x, next_y, N):
            board[next_x][next_y] = move_count
            if solve_knights_tour_util(N, board, next_x, next_y, move_count + 1, move_x, move_y):
                return True
            else:
                board[next_x][next_y] = -1  # Geri izleme

    return False

def print_solution(board):
    """Çözümü yazdırır."""
    for row in board:
        print(" ".join(map(str, row)))

if __name__ == '__main__':
    N = 8  # Tahta boyutu
    solve_knights_tour(N)
